    .then((res) => res.json())
    .then((res) => console.log(res))
    .catch(console.error);

function ApartmentGrid() {
    return (
        <div className="grid">
            <Apartment />
            <Apartment />
            <Apartment />
            <Apartment />
            <Apartment />
            <Apartment />
        </div>
    );
}

export default ApartmentGrid;
